import{_ as a,o as s,c as i,ai as r}from"./chunks/framework.DIUhWiTt.js";const h=JSON.parse('{"title":"Enumeración automatizada - Tools","description":"","frontmatter":{},"headers":[],"relativePath":"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/1.enumeracion-automatizada-tools.md","filePath":"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/1.enumeracion-automatizada-tools.md"}'),t={name:"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/1.enumeracion-automatizada-tools.md"};function n(o,e,l,c,d,u){return s(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="enumeracion-automatizada-tools" tabindex="-1">Enumeración automatizada - Tools <a class="header-anchor" href="#enumeracion-automatizada-tools" aria-label="Permalink to “Enumeración automatizada - Tools”">​</a></h1><p>Existen varios scripts para realizar la enumeración del sistema de manera similar a las vistas en la tarea anterior. Estas herramientas pueden acortar el tiempo del proceso de enumeración y descubrir diferentes vectores potenciales de escalada de privilegios. Sin embargo, recuerde que las herramientas automatizadas a veces pueden pasar por alto la escalada de privilegios.</p><p>A continuación se muestran algunas herramientas que se utilizan comúnmente para identificar vectores de escalada de privilegios. Siéntase libre de ejecutarlos contra cualquiera de las máquinas en esta sala y ver si los resultados coinciden con los vectores de ataque discutidos.</p><h4 id="winpeas" tabindex="-1">WinPEAS <a class="header-anchor" href="#winpeas" aria-label="Permalink to “WinPEAS”">​</a></h4><p>WinPEAS es un script desarrollado para enumerar el sistema de destino y descubrir rutas de escalada de privilegios. Puede encontrar más información sobre winPEAS y descargar el ejecutable precompilado o un script .bat. WinPEAS ejecutará comandos similares a los enumerados en la tarea anterior e imprimirá su resultado. El resultado de winPEAS puede ser extenso y, en ocasiones, difícil de leer. Por eso sería una buena práctica redirigir siempre la salida a un archivo, como se muestra a continuación:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\&gt; winpeas.exe &gt; outputfile.txt</span></span></code></pre></div><p>WinPEAS se puede descargar <a href="https://github.com/carlospolop/PEASS-ng/tree/master/winPEAS" target="_blank" rel="noreferrer">aquí</a> .</p><h4 id="privesccheck" tabindex="-1">PrivescCheck <a class="header-anchor" href="#privesccheck" aria-label="Permalink to “PrivescCheck”">​</a></h4><p>PrivescCheck es un script de PowerShell que busca la escalada de privilegios comunes en el sistema de destino. Proporciona una alternativa a WinPEAS sin requerir la ejecución de un archivo binario.</p><h4 id="privesccheck-se-puede-descargar-aqui" tabindex="-1">PrivescCheck se puede descargar <a href="https://github.com/itm4n/PrivescCheck" target="_blank" rel="noreferrer">aquí</a> . <a class="header-anchor" href="#privesccheck-se-puede-descargar-aqui" aria-label="Permalink to “PrivescCheck se puede descargar aquí .”">​</a></h4><p><strong>Recordatorio</strong> : para ejecutar PrivescCheck en el sistema de destino, es posible que deba omitir las restricciones de la política de ejecución. Para lograr esto, puede utilizar el <code>Set-ExecutionPolicy</code>cmdlet como se muestra a continuación.</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PS C:\\&gt; Set-ExecutionPolicy Bypass -Scope process -Force</span></span>
<span class="line"><span>PS C:\\&gt; . .\\PrivescCheck.ps1</span></span>
<span class="line"><span>PS C:\\&gt; Invoke-PrivescCheck</span></span></code></pre></div><h4 id="wes-ng-windows-exploit-suggester-next-generation" tabindex="-1">WES-NG: Windows Exploit Suggester - Next Generation <a class="header-anchor" href="#wes-ng-windows-exploit-suggester-next-generation" aria-label="Permalink to “WES-NG: Windows Exploit Suggester - Next Generation”">​</a></h4><p>Algunos scripts que sugieren exploits (por ejemplo, winPEAS) requerirán que los cargue en el sistema de destino y los ejecute allí. Esto puede hacer que el software antivirus los detecte y los elimine. Para evitar hacer ruido innecesario que pueda llamar la atención, es posible que prefieras usar WES-NG, que se ejecutará en tu máquina atacante.</p><p>WES-NG es un script de Python que se puede encontrar y descargar <a href="https://github.com/bitsadmin/wesng" target="_blank" rel="noreferrer">aquí</a> .</p><p>Una vez instalado, y antes de usarlo, escriba el <code>wes.py --update</code>comando para actualizar la base de datos. El script hará referencia a la base de datos que crea para comprobar si faltan parches que puedan provocar una vulnerabilidad que pueda utilizar para elevar sus privilegios en el sistema de destino.</p><p>Para utilizar el script, deberá ejecutar el <code>systeminfo</code> comando en el sistema de destino. No olvide dirigir la salida a un archivo .txt que deberá mover a su máquina atacante.</p><p>Una vez hecho esto, wes.py se puede ejecutar de la siguiente manera;</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>user@kali$ wes.py systeminfo.txt</span></span></code></pre></div>`,19)])])}const m=a(t,[["render",n]]);export{h as __pageData,m as default};
